class Solution {
    int count = 0, result = 0;

    public int kthSmallest(TreeNode root, int k) {
        count = k;
        inorder(root);
        return result;
    }

    private void inorder(TreeNode node) {
        if (node == null || count < 0) return;
        inorder(node.left);
        if (--count == 0) { result = node.val; return; }
        inorder(node.right);
    }
}
